SELECT C.SEMESTRE FROM CALC_HORA_AULA_MEDIA C JOIN SERVIDOR S ON S.PK_SIAPE = C.SIAPE WHERE C.ANO = 2023 AND LOWER(C.SIGLA_CAMPUS) = LOWER('val') AND ((LOWER(C.AREA_INGRESSO) LIKE LOWER('%engenharia eletrica%')) OR (LOWER(C.AREA_INGRESSO) LIKE LOWER('%engenharia eletrica%'))) AND LOWER(S.CONTRATO) = LOWER('efetivos') GROUP BY C.SEMESTRE HAVING COUNT(DISTINCT C.SIAPE) = 7 ORDER BY C.SEMESTRE ASC